        ["algo" => 571, "uuid" => "54326e", "name" => "hash-drbg", "type" => "drbg", "status" => "active", "title" => "Hash-DRBG", "description_md" => "Hash-DRBG is a NIST SP 800-90A standard DRBG using a hash function (SHA-256 or SHA-512).\n\nHash-DRBG is used in software environments preferring hash-based constructions over block ciphers. Less common than CTR-DRBG and HMAC-DRBG in practice.", "mental_model" => "SHA-256/512-based DRBG -- NIST SP 800-90A hash variant.", "purpose" => ["hash-based deterministic rng"], "good_for" => ["fips drbg hash-based variant", "software-only environments"], "avoid_for" => ["hardware aes available (ctr-drbg faster)", "most general (hmac-drbg more common)"], "pros" => ["nist sp 800-90a standard", "hash-based (software friendly)", "no cipher dependency"], "cons" => ["slower than ctr-drbg with aes-ni", "less deployed than ctr/hmac"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Hash based; Grover reduces to 128-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Software Hash-DRBG key generation", "input" => ["entropy" => "256-bit seed"], "output" => ["random" => "hash-drbg output"]], "flow" => ["hash-based state update", "generate: sha-256 counter hash"], "related" => ["hmac-drbg", "ctr-drbg"]],
        ["algo" => 572, "uuid" => "20d784", "name" => "hmac-drbg", "type" => "drbg", "status" => "active", "title" => "HMAC-DRBG", "description_md" => "HMAC-DRBG is a NIST SP 800-90A standard DRBG using HMAC (typically HMAC-SHA-256) for state update and output generation.\n\nHMAC-DRBG is widely used in deterministic signature schemes (RFC 6979 deterministic ECDSA), TLS, and software crypto libraries. RFC 6979 uses HMAC-DRBG to derive deterministic nonces for ECDSA.", "mental_model" => "HMAC-SHA-256 based DRBG -- RFC 6979 deterministic ECDSA nonce standard.", "purpose" => ["hmac-based deterministic rng"], "good_for" => ["rfc 6979 deterministic ecdsa nonce", "fips drbg", "deterministic test vectors"], "avoid_for" => ["high performance (ctr-drbg aes-ni faster)"], "pros" => ["nist sp 800-90a standard", "rfc 6979 (deterministic ecdsa)", "widely deployed", "no block cipher needed"], "cons" => ["slower than ctr-drbg with aes-ni"], "difficulty" => 2, "security" => 5, "quantum_impact" => "HMAC based; Grover reduced.", "post_quantum_status" => 3, "example" => ["scenario" => "RFC 6979 ECDSA deterministic nonce", "input" => ["priv_key" => "32-byte", "message_hash" => "32-byte"], "output" => ["nonce" => "deterministic k"]], "flow" => ["hmac-drbg instantiate with priv key + msg hash", "generate k = deterministic nonce for ecdsa"], "related" => ["ctr-drbg", "hash-drbg", "det-ecdsa"]],
        ["algo" => 573, "uuid" => "94b0e9", "name" => "csprng-system", "type" => "rng", "status" => "active", "title" => "OS CSPRNG", "description_md" => "OS CSPRNG (Cryptographically Secure Pseudo-Random Number Generator) refers to the kernel-provided CSPRNG: /dev/urandom (Linux), CryptGenRandom (Windows), or arc4random (BSD).\n\nThe OS CSPRNG is the recommended source for cryptographic randomness in applications. Feeds from hardware entropy (CPU jitter, interrupt timing, hardware RNG). Modern OS CSPRNGs are universally suitable.", "mental_model" => "OS kernel CSPRNG -- /dev/urandom, getentropy, arc4random. Always use this as randomness source.", "purpose" => ["application cryptographic randomness source"], "good_for" => ["all cryptographic key generation", "iv/nonce generation", "any application random"], "avoid_for" => ["entropy source for HSM (use trng)", "user-space seeding (OS handles this)"], "pros" => ["os-managed", "reseeds automatically", "universally available", "hardware entropy fed"], "cons" => ["blocking possible at boot (use getrandom)", "not hardware TRNG directly"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Entropy sources typically quantum-resistant.", "post_quantum_status" => 4, "example" => ["scenario" => "Generate AES-256 key", "input" => ["request" => "32 bytes"], "output" => ["key" => "32 cryptographically random bytes"]], "flow" => ["read /dev/urandom or call getentropy()", "kernel feeds: cpu jitter + interrupt timing + hwrng"], "related" => ["getrandom", "getentropy", "trng", "rdrand", "jitterentropy"]],
        ["algo" => 574, "uuid" => "d1cd64", "name" => "trng", "type" => "rng", "status" => "active", "title" => "True RNG (TRNG)", "description_md" => "TRNG (True Random Number Generator) generates randomness from physical entropy sources (thermal noise, shot noise, quantum effects). Provides non-deterministic entropy.\n\nTRNGs are used in HSMs, hardware security chips, and system entropy pools. The TRNG feeds the OS entropy pool which then drives the CSPRNG. Often post-processed through a DRBG conditioner.", "mental_model" => "Physical entropy source -- hardware noise feeding OS entropy pool and HSM seeding.", "purpose" => ["hardware physical entropy generation"], "good_for" => ["hsm seed entropy", "os entropy pool", "key ceremony entropy"], "avoid_for" => ["application use (use csprng-system instead)", "deterministic (DRBG for that)"], "pros" => ["true physical entropy", "non-deterministic", "hsm/hw security standard"], "cons" => ["low throughput (hardware)", "needs post-processing/conditioning"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Physical entropy; quantum-resistant source.", "post_quantum_status" => 5, "example" => ["scenario" => "HSM key generation seeding", "input" => ["source" => "thermal noise diode"], "output" => ["entropy" => "true random bits"]], "flow" => ["harvest physical noise", "post-process with conditioner (sha/aes)", "feed ctr-drbg or os entropy pool"], "related" => ["rdrand", "rdseed", "jitterentropy", "csprng-system"]],
        ["algo" => 575, "uuid" => "9d5862", "name" => "entropy-pool", "type" => "rng", "status" => "active", "title" => "Entropy Pool", "description_md" => "Entropy Pool is the OS kernel construct that collects entropy from multiple sources (interrupt timing, CPU jitter, hardware RNG, boot events) and mixes them into a pool feeding the CSPRNG.\n\nLinux entropy pool uses BLAKE2s/ChaCha20 (since kernel 5.17). BSD uses Fortuna-based pool. The entropy pool ensures the CSPRNG is properly seeded even at boot.", "mental_model" => "OS entropy collection pool -- mixes interrupt timing, cpu jitter, hwrng into CSPRNG seed.", "purpose" => ["os entropy aggregation for csprng"], "good_for" => ["understanding os randomness architecture"], "avoid_for" => ["direct application use (use csprng-system)"], "pros" => ["multi-source mixing", "automatic reseeding", "linux/bsd standard"], "cons" => ["theoretical (not directly called by apps)"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Mixed entropy; quantum-resistant.", "post_quantum_status" => 4, "example" => ["scenario" => "Linux entropy pool at boot", "input" => ["sources" => "interrupts + tsc jitter + hwrng"], "output" => ["seed" => "chacha20 drbg seeded"]], "flow" => ["collect entropy events -> pool", "mix with blake2s", "seed chacha20 csprng"], "related" => ["csprng-system", "jitterentropy", "rdrand", "trng"]],
        ["algo" => 576, "uuid" => "791a74", "name" => "reseed-scheduler", "type" => "rng", "status" => "active", "title" => "Reseed Scheduler", "description_md" => "Reseed Scheduler manages the periodic reseeding of DRBGs from entropy sources. NIST SP 800-90A specifies reseed intervals -- CTR-DRBG must reseed after 2^48 generate calls.\n\nProper reseed scheduling ensures DRBG security even under compromise scenarios (forward secrecy through reseeding).", "mental_model" => "DRBG reseed lifecycle management -- SP 800-90A reseed interval, forward secrecy.", "purpose" => ["drbg reseed lifecycle management"], "good_for" => ["fips drbg compliance", "long-running drbg management"], "avoid_for" => ["direct use (component of DRBG)"], "pros" => ["forward secrecy via reseeding", "nist sp 800-90a compliance"], "cons" => ["conceptual component, not standalone"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Reseed improves forward secrecy.", "post_quantum_status" => 4, "example" => ["scenario" => "CTR-DRBG reseed after 2^32 outputs", "input" => ["new_entropy" => "256-bit from trng"], "output" => ["reseeded_drbg" => "forward-secret state"]], "flow" => ["track generate count", "at interval: request entropy from OS", "update DRBG state with fresh entropy"], "related" => ["ctr-drbg", "hmac-drbg", "fortuna"]],
        ["algo" => 577, "uuid" => "cf92b8", "name" => "rdrand", "type" => "rng", "status" => "active", "title" => "RDRAND", "description_md" => "RDRAND is an Intel/AMD x86 CPU instruction that returns hardware random numbers from an on-chip CSPRNG seeded by a hardware entropy source.\n\nRDRAND is used to seed OS entropy pools and directly in high-throughput applications. Controversy exists over Intel's TRNG design -- RDRAND output should be mixed with other entropy sources, not used exclusively.", "mental_model" => "Intel/AMD CPU hardware RNG -- seed OS pool, not sole entropy source (trust concerns).", "purpose" => ["cpu hardware random instruction"], "good_for" => ["fast hardware entropy contribution to pool", "x86 available entropy source"], "avoid_for" => ["sole entropy source (mix with jitterentropy)", "non-x86 (use trng/rdseed)"], "pros" => ["cpu instruction fast", "hardware rng", "widely available x86"], "cons" => ["intel trust controversy", "opaque hardware", "mix with other sources"], "difficulty" => 1, "security" => 4, "quantum_impact" => "CSPRNG based; classical.", "post_quantum_status" => 3, "example" => ["scenario" => "Linux entropy pool RDRAND contribution", "input" => ["cpu" => "intel/amd x86"], "output" => ["random" => "64-bit hardware random"]], "flow" => ["rdrand instruction -> on-chip csprng output", "mixed into OS entropy pool with other sources"], "related" => ["rdseed", "trng", "jitterentropy", "entropy-pool"]],
        ["algo" => 578, "uuid" => "a15465", "name" => "rdseed", "type" => "rng", "status" => "active", "title" => "RDSEED", "description_md" => "RDSEED is an Intel/AMD x86 instruction that returns raw hardware entropy (unprocessed) from the on-chip entropy source, suitable for seeding external DRBGs.\n\nUnlike RDRAND (CSPRNG output), RDSEED gives raw entropy -- more suitable for seeding external DRBGs. Same controversy as RDRAND regarding Intel hardware trust.", "mental_model" => "Raw hardware entropy instruction -- unlike RDRAND (CSPRNG), RDSEED gives raw entropy for seeding.", "purpose" => ["raw cpu entropy for drbg seeding"], "good_for" => ["seeding external drbg from cpu entropy", "more raw than rdrand"], "avoid_for" => ["sole entropy source (same trust issues)", "general random (use rdrand or csprng)"], "pros" => ["raw entropy (not csprng output)", "x86 widely available", "good for seeding"], "cons" => ["same intel trust concerns as rdrand", "slower than rdrand (raw)"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Raw entropy source.", "post_quantum_status" => 3, "example" => ["scenario" => "Seed CTR-DRBG with RDSEED", "input" => ["cpu" => "intel broadwell+"], "output" => ["seed_bytes" => "raw hardware entropy"]], "flow" => ["rdseed instruction -> raw entropy bits", "condition + seed DRBG state"], "related" => ["rdrand", "trng", "ctr-drbg"]],
        ["algo" => 579, "uuid" => "3a851e", "name" => "jitterentropy", "type" => "rng", "status" => "active", "title" => "Jitter Entropy", "description_md" => "Jitter Entropy (jitterentropy-rngd) generates entropy from CPU execution time jitter -- slight variations in CPU cache/pipeline timing are unpredictable and provide true entropy.\n\nJitterentropy is used in Linux kernel (since 4.2), FIPS-validated entropy sources, and embedded systems without hardware RNG. Does not rely on hardware TRNG instructions. FIPS 140-2 approved entropy source.", "mental_model" => "CPU timing jitter entropy -- FIPS-approved entropy, no hardware TRNG needed, Linux kernel.", "purpose" => ["software entropy from cpu jitter"], "good_for" => ["fips 140 entropy source without trng", "embedded without hwrng", "linux entropy pool supplement"], "avoid_for" => ["high-throughput entropy (hardware trng faster)"], "pros" => ["fips 140-2 approved entropy", "no hardware trng needed", "linux kernel standard", "rdrand-independent"], "cons" => ["slower than hardware trng", "os scheduler may reduce jitter"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Physical timing entropy; quantum-resistant source.", "post_quantum_status" => 5, "example" => ["scenario" => "FIPS entropy on VM without RDRAND", "input" => ["source" => "cpu cache timing jitter"], "output" => ["entropy" => "conditioned jitter entropy"]], "flow" => ["collect cpu timing jitter measurements", "apply conditioning (sha-256)", "feed entropy pool"], "related" => ["trng", "rdrand", "entropy-pool", "csprng-system"]],
        ["algo" => 581, "uuid" => "fd51c3", "name" => "fortuna", "type" => "drbg", "status" => "active", "title" => "Fortuna", "description_md" => "Fortuna is a CSPRNG designed by Bruce Schneier and Niels Ferguson. Uses multiple entropy pools (32 pools) with reseed scheduling to recover from compromised state. Used in macOS, iOS, and FreeBSD kernels.\n\nFortuna's design ensures that even if the CSPRNG state is compromised, it recovers within a bounded time as new entropy accumulates. macOS/iOS use Fortuna as the kernel CSPRNG.", "mental_model" => "Fortuna CSPRNG -- macOS/iOS kernel RNG, 32-pool progressive reseeding, compromise recovery.", "purpose" => ["fortuna kernel csprng"], "good_for" => ["macos/ios fortuna compatible", "csprng with compromise recovery"], "avoid_for" => ["direct application use (use csprng-system)"], "pros" => ["compromise recovery guaranteed", "macos/ios standard", "32-pool design", "sha-256 + aes"], "cons" => ["complex 32-pool design", "direct app use not needed"], "difficulty" => 3, "security" => 5, "quantum_impact" => "SHA-256 + AES based; 128-bit quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "macOS kernel Fortuna CSPRNG", "input" => ["pools" => "32 entropy pools", "events" => "interrupts+hwrng"], "output" => ["random" => "cryptographic random bytes"]], "flow" => ["entropy events distributed to 32 pools", "reseed: pool 0 every request, pool i every 2^i requests", "generate: aes-256-ctr from seeded key"], "related" => ["ctr-drbg", "yarrow", "csprng-system"]],
