        ["algo" => 586, "uuid" => "50716d", "name" => "getrandom", "type" => "rng", "status" => "new", "title" => "getrandom()", "description_md" => "getrandom() is a Linux system call (Linux 3.17+) that provides cryptographically secure random bytes from the kernel CSPRNG. Blocks until entropy pool is initialized (unlike /dev/urandom which returns before initialization).\n\ngetrandom() is the recommended way to get randomness in modern Linux applications. GRND_NONBLOCK flag avoids blocking if needed. Used by glibc arc4random() since glibc 2.36.", "mental_model" => "Modern Linux random syscall -- blocks until initialized, better than /dev/urandom. Use this.", "purpose" => ["modern linux secure random api"], "good_for" => ["linux key/nonce generation", "modern glibc randomness", "blocking until pool initialized"], "avoid_for" => ["non-linux (getentropy on bsd/macos)", "early boot before pool init (GRND_INSECURE)"], "pros" => ["blocks until initialized (safe)", "modern linux standard", "no fd management", "glibc arc4random uses this"], "cons" => ["linux-specific", "can block at early boot"], "difficulty" => 1, "security" => 5, "quantum_impact" => "OS entropy backed.", "post_quantum_status" => 4, "example" => ["scenario" => "Linux key generation", "input" => ["bytes" => 32], "output" => ["key" => "32 cryptographically random bytes"]], "flow" => ["getrandom(buf, 32, 0) -> kernel csprng -> 32 bytes"], "related" => ["getentropy", "csprng-system", "chacha20-drbg"]],
        ["algo" => 587, "uuid" => "067330", "name" => "getentropy", "type" => "rng", "status" => "new", "title" => "getentropy()", "description_md" => "getentropy() is a POSIX-compatible API for obtaining cryptographic randomness (OpenBSD since 5.6, Linux since glibc 2.25, macOS 10.12). Limited to 256 bytes per call.\n\ngetentropy() is the most portable secure randomness API across OpenBSD, macOS, and Linux. Simplest and safest API for getting up to 256 bytes of randomness.", "mental_model" => "Portable secure random API -- OpenBSD/macOS/Linux, max 256 bytes, safest API.", "purpose" => ["portable posix secure random api"], "good_for" => ["portable posix secure randomness", "openbsd/macos/linux", "seed for drbg"], "avoid_for" => ["large amounts (max 256 bytes per call)", "linux-only (getrandom more flexible)"], "pros" => ["most portable (openbsd/macos/linux)", "simplest api", "safe (blocks until initialized)", "max 256 bytes (never blocks long)"], "cons" => ["max 256 bytes per call", "not on older systems"], "difficulty" => 1, "security" => 5, "quantum_impact" => "OS entropy backed.", "post_quantum_status" => 4, "example" => ["scenario" => "Portable key generation", "input" => ["bytes" => 32], "output" => ["key" => "32 bytes"]], "flow" => ["getentropy(buf, 32) -> OS CSPRNG -> 32 bytes"], "related" => ["getrandom", "csprng-system", "bcryptgenrandom"]],
        ["algo" => 588, "uuid" => "42412c", "name" => "bcryptgenrandom", "type" => "rng", "status" => "new", "title" => "BCryptGenRandom", "description_md" => "BCryptGenRandom is the modern Windows CNG (Cryptography API: Next Generation) function for generating cryptographically secure random numbers. Replacement for deprecated CryptGenRandom.\n\nBCryptGenRandom is the recommended Windows randomness API since Windows Vista. Uses the Windows kernel RNG.", "mental_model" => "Modern Windows CNG randomness API -- replacement for CryptGenRandom.", "purpose" => ["modern windows cryptographic rng api"], "good_for" => ["windows key/nonce generation", "cng-based windows crypto"], "avoid_for" => ["non-windows (getrandom/getentropy)", "legacy capi (migrate to cng)"], "pros" => ["modern windows cng standard", "replaces deprecated cryptgenrandom", "kernel rng backed"], "cons" => ["windows-only"], "difficulty" => 1, "security" => 5, "quantum_impact" => "OS entropy backed.", "post_quantum_status" => 4, "example" => ["scenario" => "Windows AES key generation", "input" => ["bytes" => 32], "output" => ["key" => "32 random bytes"]], "flow" => ["BCryptGenRandom(NULL, buf, 32, BCRYPT_USE_SYSTEM_PREFERRED_RNG)"], "related" => ["cryptgenrandom", "csprng-system", "getentropy"]],
        ["algo" => 593, "uuid" => "8d633d", "name" => "nist-randomness-beacon", "type" => "rng", "status" => "new", "title" => "NIST Randomness Beacon", "description_md" => "The NIST Randomness Beacon is a public service providing externally verifiable random values every 60 seconds. Uses two hardware entropy sources with SHA-512 and RSA-PSS signatures for verifiability.\n\nNIST Beacon is used for public verifiable randomness in lotteries, audits, and ceremonies where unpredictability and public verifiability are both needed. Not for secret key generation.", "mental_model" => "Public verifiable random beacon -- NIST Randomness Beacon, externally verifiable 60s randomness.", "purpose" => ["public externally-verifiable randomness"], "good_for" => ["public lotteries and audits", "publicly verifiable ceremonies", "drand/pvss alternative"], "avoid_for" => ["secret key generation (public service!)", "offline applications"], "pros" => ["nist-signed verifiable", "public randomness standard", "external auditability"], "cons" => ["public -- not for secret keys", "online service dependency", "60-second granularity"], "difficulty" => 1, "security" => 4, "quantum_impact" => "RSA-PSS signatures quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Public lottery randomness", "input" => ["beacon_record" => "nist signed record"], "output" => ["random" => "publicly verifiable 512-bit value"]], "flow" => ["query nist beacon api", "verify rsa-pss signature on record", "use beacon value as public randomness"], "related" => ["pvss", "trng", "qrng"]],
        ["algo" => 594, "uuid" => "d27ebc", "name" => "qrng", "type" => "rng", "status" => "new", "title" => "QRNG", "description_md" => "QRNG (Quantum Random Number Generator) uses quantum mechanical phenomena (photon arrival timing, quantum vacuum fluctuations, radioactive decay) to generate true random numbers.\n\nQRNG provides the highest quality entropy, provably random by quantum physics. Used in high-security HSMs, banking, and research. ID Quantique and other vendors offer commercial QRNG hardware.", "mental_model" => "Quantum entropy source -- provably random by quantum physics, highest quality TRNG.", "purpose" => ["quantum true random number generation"], "good_for" => ["highest security entropy source", "quantum-certified randomness", "key ceremony entropy"], "avoid_for" => ["general (os csprng sufficient)", "cost-sensitive (hardware qrng expensive)"], "pros" => ["quantum physics entropy (provably random)", "highest quality true random", "commercial hsm certified"], "cons" => ["expensive hardware", "trust in manufacturer implementation", "not needed for most applications"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Quantum entropy source -- quantum-safe randomness.", "post_quantum_status" => 5, "example" => ["scenario" => "QRNG-seeded HSM key generation", "input" => ["source" => "photon arrival timing"], "output" => ["entropy" => "quantum random bits"]], "flow" => ["quantum event detection", "classical conditioning and post-processing", "feed entropy pool or direct output"], "related" => ["trng", "rdseed", "nist-randomness-beacon"]],
        ["algo" => 595, "uuid" => "6279ab", "name" => "blockchain-vrf", "type" => "rng", "status" => "new", "title" => "Blockchain VRF", "description_md" => "Blockchain VRF (Verifiable Random Function) generates provably random values on-chain using cryptographic VRF (typically ECVRF on secp256k1 or ed25519). Used in Chainlink VRF, Algorand, Cardano, and Ethereum RANDAO.\n\nBlockchain VRF provides verifiable, manipulation-resistant on-chain randomness for smart contracts. The VRF proof guarantees the output was computed from the committed seed without manipulation.", "mental_model" => "On-chain verifiable random function -- Chainlink VRF, Algorand/Cardano/ETH RANDAO, manipulation-resistant.", "purpose" => ["verifiable on-chain smart contract randomness"], "good_for" => ["smart contract randomness", "chainlink vrf", "blockchain lottery/nft/game randomness"], "avoid_for" => ["off-chain (use os csprng)", "secret randomness (on-chain public)"], "pros" => ["manipulation-resistant on-chain", "verifiable proof", "chainlink vrf standard", "decentralized"], "cons" => ["on-chain cost (gas)", "requires oracle (chainlink)", "finality delay"], "difficulty" => 3, "security" => 4, "quantum_impact" => "EC VRF quantum-vulnerable; PQ VRF in research.", "post_quantum_status" => 1, "example" => ["scenario" => "Chainlink VRF NFT mint randomness", "input" => ["request_id" => "on-chain request", "vrf_key" => "oracle key"], "output" => ["random" => "verifiable random word + proof"]], "flow" => ["contract requests randomness with seed", "chainlink vrf oracle: vrf(key, seed) -> output + proof", "contract verifies proof on-chain"], "related" => ["pvss", "nist-randomness-beacon", "hmac-drbg"]],
